import React from "react";
import Navbar from "./components/Navbar";
import Home from "./components/Home";
import About from "./components/About";
import PracticeAreas from "./components/PracticeAreas";
import Professionals from "./components/Professionals";
import News from "./components/News";
import Gallery from "./components/Gallery";
import Contact from "./components/Contact";
import { BrowserRouter as Router, Route, Routes } from "react-router-dom"; // Import Router, Route, and Routes
import NewsDetail from "./components/NewsDetail"; // Import NewsDetail component
import "./styles.css"; // Import global styles

function App() {
  return (
    <Router> {/* Wrap your entire app with Router */}
      <div>
        <Navbar />
        <section id="HOME" className="section">
          <Home />
        </section>
        <section id="ABOUT US" className="section">
          <About />
        </section>
        <section id="AREAS OF PRACTICE" className="section">
          <PracticeAreas />
        </section>
        <section id="OUR PROFESSIONALS" className="section">
          <Professionals />
        </section>
        <section id="NEWS & ARTICLES" className="section">
          <News />
        </section>
        <section id="GALLERY" className="section">
          <Gallery />
        </section>
        <section id="CONTACT US" className="section">
          <Contact />
        </section>

        {/* Add Routes for News and NewsDetail */}
        <Routes>
          <Route path="/news" element={<News />} /> {/* News page route */}
          <Route path="/news/:id" element={<NewsDetail />} /> {/* News detail route */}
        </Routes>
      </div>
    </Router>
  );
}

export default App;
